# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request
from collections import Counter
import pandas as pd
from sklearn.model_selection import train_test_split
from sklearn.linear_model import LogisticRegression
from sklearn.preprocessing import LabelEncoder
from PIL import Image
import numpy as np
import os

app = Flask(__name__)
database = {}

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return "No file part"

    file = request.files['file']
    if file.filename == '':
        return "No selected file"

    if file:
        filename = file.filename
        data = np.array(Image.open(file))
        if filename in database:
            database[filename]['data'].append(data)
        else:
            database[filename] = {'data': [data], 'label': []}
        return 'File uploaded successfully'

@app.route('/label', methods=['POST'])
def receive_label():
    filename = request.form.get('file')
    label = request.form.get('label')
    
    if filename not in database:
        return "No such file"
    
    database[filename]['label'].append(label)
    return 'Label received successfully'

@app.route('/aggregate', methods=['GET'])
def aggregate_labels():
    aggregated_data = []
    aggregated_label = []
    le = LabelEncoder()

    for key in database:
        counter = Counter(database[key]['label'])
        mode = counter.most_common(1)[0][0]
        
        for data in database[key]['data']:
            aggregated_data.append(data.flatten())
            aggregated_label.append(mode)
            
    X = np.array(aggregated_data)
    y = le.fit_transform(aggregated_label)

    model = LogisticRegression().fit(X, y)
    return 'Model trained successfully'

if __name__ == '__main__':
    app.run(debug=True)